        }

        .news-item {
            background: #f8f9fa;
            border-radius: 8px;
            padding: 15px;
            margin-bottom: 15px;
            border-left: 4px solid #667eea;
        }

        .news-item-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 10px;
        }

        .news-item-header h3 {
            color: #333;
            font-size: 16px;
        }

        .btn-remove {
            background: #ff4757;
            color: white;
            border: none;
            padding: 6px 12px;
            border-radius: 6px;
            cursor: pointer;
            font-size: 12px;
        }

        .btn-remove:hover {
            background: #ff3344;
        }

        .btn-add {
            background: #667eea;
            color: white;
            border: none;
            padding: 12px 24px;
            border-radius: 8px;
            cursor: pointer;
            font-size: 14px;
            width: 100%;
            margin-top: 10px;
            transition: background 0.3s;
        }

        .btn-add:hover {
            background: #5568d3;
        }

        .btn-download {
            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
            color: white;
            border: none;
            padding: 15px 30px;
            border-radius: 8px;
            cursor: pointer;
            font-size: 16px;
            font-weight: 600;
            width: 100%;
            margin-top: 20px;
            transition: transform 0.3s, box-shadow 0.3s;
        }

        .btn-download:hover {
            transform: translateY(-2px);
            box-shadow: 0 5px 20px rgba(102, 126, 234, 0.4);
        }

        /* 预览区域 */
        .preview-panel {
            background: white;
            border-radius: 16px;
            padding: 30px;
            box-shadow: 0 10px 40px rgba(0,0,0,0.2);
            display: flex;
            flex-direction: column;
            align-items: center;
        }

        .preview-panel h2 {
            color: #333;
            margin-bottom: 20px;
            font-size: 20px;
            border-bottom: 2px solid #667eea;
            padding-bottom: 10px;
            width: 100%;
            text-align: center;
        }

        #preview-container {
            background: white;
            width: 540px;
            padding: 40px;
            border: 3px solid #000;
        }

        #preview-content {
            background: white;
        }

        .preview-header {
            text-align: center;
            margin-bottom: 20px;
        }

        .preview-title {
            font-size: 48px;
            font-weight: bold;
            color: #000;
            margin-bottom: 15px;
        }

        .preview-date {
            font-size: 28px;
            color: #000;
            border-top: 3px solid #000;
            padding-top: 15px;
            margin-top: 15px;
        }

        .preview-news-list {
            margin-top: 25px;
        }

        .preview-news-item {
            margin-bottom: 25px;
        }

        .preview-news-title {
            font-size: 20px;
            font-weight: bold;
            color: #000;
            margin-bottom: 10px;
        }

        .preview-news-content {
            font-size: 16px;
            color: #000;
            line-height: 1.6;
            margin-bottom: 8px;
        }

        .preview-news-source {
            font-size: 14px;
            color: #888;
        }

        .tips {
            margin-top: 20px;
            padding: 15px;
            background: #fff3cd;
            border-radius: 8px;
            border-left: 4px solid #ffc107;
            font-size: 13px;
            color: #856404;
        }

        .tips strong {
            display: block;
            margin-bottom: 5px;
        }
    </style>
</head>
<body>
    <div class="container">
        <h1>📰 AI 资讯快报生成器</h1>

        <div class="main-content">
            <!-- 编辑面板 -->
            <div class="editor-panel">
                <h2>✏️ 编辑内容</h2>

                <div class="form-group">
                    <label>主标题</label>
                    <input type="text" id="mainTitle" value="AI 资讯快报" oninput="updatePreview()">
                </div>

                <div class="form-group">
                    <label>日期</label>
                    <input type="text" id="newsDate" value="2026.04.04" oninput="updatePreview()">
                </div>

                <div id="newsItems">
                    <!-- 动态生成的新闻项 -->
                </div>

                <button class="btn-add" onclick="addNewsItem()">+ 添加一条资讯</button>
                <button class="btn-download" onclick="downloadImage()">📸 导出图片</button>

                <div class="tips">
                    <strong>💡 使用提示：</strong>
                    1. 左侧编辑内容，右侧实时预览<br>
                    2. 可添加/删除任意条资讯<br>
                    3. 点击"导出图片"下载 PNG 文件<br>
                    4. 图片尺寸：1080×1440（小红书竖版）
                </div>
            </div>

            <!-- 预览面板 -->
            <div class="preview-panel">
                <h2>👁️ 实时预览</h2>
                <div id="preview-container">
                    <div id="preview-content">
                        <div class="preview-header">
                            <div class="preview-title" id="previewTitle">AI 资讯快报</div>
                            <div class="preview-date" id="previewDate">2026.04.04</div>
                        </div>
                        <div class="preview-news-list" id="previewNewsList">
                            <!-- 预览内容 -->
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>

    <script>
        // 默认新闻数据
        const defaultNews = [
            {
                title: "Claude Code 被中国 00 后开盒",
                content: "一位中国 00 后开发者逆向工程 Claude Code，并公开怒怼 Anthropic 窃取用户代码。开源社区与商业闭源的矛盾再次升级，代码安全话题成为焦点。",
                source: "量子位"
            },
            {
                title: "阿里千问 3.6 登顶中国编程模型榜首",
                content: "全球权威大模型盲测榜单公布，Qwen3.6-Plus 成为中国最强编程模型，在 coding 能力上首次登顶，悟空已率先接入。",
                source: "量子位"
            },
            {
                title: "字节豆包日消耗 120 万亿 Tokens",
                content: "豆包大模型每日 token 消耗量达到惊人级别，AI 应用的算力成本问题再次成为焦点，商业化路径待解。",
                source: "AI 前沿观察"
            }
        ];

        // 初始化
        function init() {
            defaultNews.forEach((news, index) => {
                addNewsItem(news.title, news.content, news.source);
            });
            updatePreview();
        }

        // 添加新闻项
        function addNewsItem(title = '', content = '', source = '') {
            const container = document.getElementById('newsItems');
            const index = container.children.length + 1;

            const item = document.createElement('div');
            item.className = 'news-item';
            item.innerHTML = `
                <div class="news-item-header">
                    <h3>资讯 ${index}</h3>
                    <button class="btn-remove" onclick="removeNewsItem(this)">删除</button>
                </div>
                <div class="form-group">
                    <label>标题</label>
                    <input type="text" value="${title}" placeholder="输入资讯标题" oninput="updatePreview()">
                </div>
                <div class="form-group">
                    <label>内容</label>
                    <textarea placeholder="输入资讯内容" oninput="updatePreview()">${content}</textarea>
                </div>
                <div class="form-group">
                    <label>来源</label>
                    <input type="text" value="${source}" placeholder="输入来源" oninput="updatePreview()">
                </div>
            `;

            container.appendChild(item);
            updatePreview();
            updateNumbers();
        }

        // 删除新闻项
        function removeNewsItem(btn) {
            btn.closest('.news-item').remove();
            updatePreview();
            updateNumbers();
        }

        // 更新序号
        function updateNumbers() {
            const items = document.querySelectorAll('.news-item');
            items.forEach((item, index) => {
                item.querySelector('h3').textContent = `资讯 ${index + 1}`;
            });
        }

        // 更新预览
        function updatePreview() {
            // 更新标题和日期
            document.getElementById('previewTitle').textContent = document.getElementById('mainTitle').value || 'AI 资讯快报';
            document.getElementById('previewDate').textContent = document.getElementById('newsDate').value || '2026.04.04';

            // 更新新闻列表
            const newsList = document.getElementById('previewNewsList');
            const newsItems = document.querySelectorAll('.news-item');

            newsList.innerHTML = '';

            newsItems.forEach((item, index) => {
                const inputs = item.querySelectorAll('input, textarea');
                const title = inputs[0].value;
                const content = inputs[1].value;
                const source = inputs[2].value;

                if (title || content) {
                    const newsEl = document.createElement('div');
                    newsEl.className = 'preview-news-item';
                    newsEl.innerHTML = `
                        <div class="preview-news-title">${index + 1}、${title}</div>
                        <div class="preview-news-content">${content}</div>
                        ${source ? `<div class="preview-news-source">来源：${source}</div>` : ''}
                    `;
                    newsList.appendChild(newsEl);
                }
            });
        }

        // 下载图片
        function downloadImage() {
            const previewContent = document.getElementById('preview-content');

            html2canvas(previewContent, {
                scale: 2,
                backgroundColor: '#ffffff',
                logging: false,
                useCORS: true
            }).then(canvas => {
                const link = document.createElement('a');
                const date = document.getElementById('newsDate').value.replace(/\./g, '');
                link.download = `AI 资讯快报_${date}.png`;
                link.href = canvas.toDataURL('image/png');
                link.click();
            });
        }

        // 页面加载后初始化
        window.onload = init;
    </script>
</body>
</html>
"}

