<body>
    <div class="container">
        <h1>📰 AI 资讯快报生成器</h1>

        <div class="main-content">
            <!-- 编辑面板 -->
            <div class="editor-panel">
                <h2>✏️ 编辑内容</h2>

                <div class="form-group">
                    <label>主标题</label>
                    <input type="text" id="mainTitle" value="AI 资讯快报" oninput="updatePreview()">
                </div>

                <div class="form-group">
                    <label>日期</label>
                    <input type="text" id="newsDate" value="2026.04.04" oninput="updatePreview()">
                </div>

                <div class="paste-area">
                    <label style="display:block;color:#555;font-weight:600;margin-bottom:8px;font-size:14px;">
                        📋 粘贴正文（自动解析）
                    </label>
                    <textarea id="pasteContent" oninput="autoParse()" placeholder="粘贴类似以下格式的正文：

1、Claude Code 被中国 00 后开盒
一位中国 00 后开发者逆向工程 Claude Code...
来源：量子位

2、阿里千问 3.6 登顶中国编程模型榜首
全球权威大模型盲测榜单公布...
来源：量子位

3、..."></textarea>

                    <div id="statusBox" class="status-box"></div>

                    <div style="margin-top:10px;">
                        <button class="btn btn-secondary" onclick="clearPaste()">🗑️ 清空</button>
                        <button class="btn btn-primary" onclick="manualParse()">🔄 重新解析</button>
                    </div>
                </div>

                <div style="margin-top:15px;">
                    <label style="display:block;color:#555;font-weight:600;margin-bottom:8px;font-size:14px;">
                        📝 已解析 <span id="newsCount">0</span> 条资讯
                    </label>
                    <div class="news-list" id="newsList">
                        <p style="color:#999;text-align:center;padding:20px;">暂无内容，请粘贴正文</p>
                    </div>
                </div>

                <div class="download-section">
                    <button class="btn btn-success" onclick="downloadAll()">📸 下载全部图片</button>
                    <button class="btn btn-primary" onclick="downloadCurrent()">📸 下载当前页</button>
                </div>

                <div class="tips">
                    <strong>💡 使用提示：</strong>
                    1. 粘贴正文后自动解析，无需点击按钮<br>
                    2. 格式错误会红色提示，正确会绿色提示<br>
                    3. 每 2 条资讯生成 1 张图片，自动分页<br>
                    4. 图片尺寸：1080×1440（小红书竖版）
                </div>
            </div>

            <!-- 预览面板 -->
            <div class="preview-panel">
                <h2>👁️ 实时预览</h2>

                <div class="preview-controls">
                    <button class="btn btn-secondary" onclick="prevPage()" id="btnPrev">◀ 上一页</button>
                    <span class="page-indicator" id="pageIndicator">第 1 / 1 页</span>
                    <button class="btn btn-secondary" onclick="nextPage()" id="btnNext">下一页 ▶</button>
                </div>

                <div class="preview-container" id="previewContainer">
                    <!-- 动态生成预览卡片 -->
                </div>
            </div>
