<body>
    <!-- 顶部导航 -->
    <header class="header">
        <div class="header-content">
            <div class="header-title">
                <div class="logo">📰</div>
                AI 资讯快报生成器
            </div>
            <div class="header-actions">
                <button class="header-btn secondary" onclick="loadDemo()">📝 加载示例</button>
                <button class="header-btn primary" onclick="downloadAll()">📸 下载全部</button>
            </div>
        </div>
    </header>

    <!-- 主内容区 -->
    <main class="main">
        <!-- 左侧编辑面板 -->
        <div class="card">
            <div class="card-header">
                <div class="card-title">✏️ 编辑内容</div>
            </div>
            <div class="card-body">
                <div class="form-group">
                    <label class="form-label">主标题</label>
                    <input type="text" class="form-input" id="mainTitle" value="AI 资讯快报" oninput="updatePreview()">
                </div>

                <div class="form-group">
                    <label class="form-label">日期</label>
                    <input type="text" class="form-input" id="newsDate" value="2026.04.04" oninput="updatePreview()">
                </div>

                <div class="form-group">
                    <label class="form-label">📋 粘贴正文</label>
                    <textarea class="paste-textarea" id="pasteContent" oninput="autoParse()" placeholder="粘贴资讯正文，格式如下：

1、Claude Code 被中国 00 后开盒
一位中国 00 后开发者逆向工程 Claude Code...
来源：量子位

2、阿里千问 3.6 登顶中国编程模型榜首
全球权威大模型盲测榜单公布...
来源：量子位"></textarea>

                    <div id="statusBox" class="status-box"></div>

                    <div class="btn-group">
                        <button class="btn default" onclick="clearPaste()">🗑️ 清空</button>
                        <button class="btn default" onclick="manualParse()">🔄 重新解析</button>
                    </div>
                </div>

                <div class="news-list-container">
                    <div class="news-list-header">
                        <span class="news-list-title">已解析资讯</span>
                        <span class="news-count" id="newsCount">0</span>
                    </div>
                    <div class="news-list" id="newsList">
                        <div class="news-list-empty">
                            <p>暂无内容</p>
                            <p style="margin-top:8px;font-size:12px;">粘贴正文后自动解析</p>
                        </div>
                    </div>
                </div>

                <div class="download-section">
                    <div class="download-btns">
                        <button class="download-btn secondary" onclick="downloadCurrent()">📸 下载当前页</button>
                        <button class="download-btn primary" onclick="downloadAll()">📸 下载全部图片</button>
                    </div>
                </div>

                <div class="tips-box">
                    <div class="tips-box-title">💡 使用提示</div>
                    <div class="tips-box-content">
                        粘贴正文后自动解析，无需点击按钮<br>
                        格式错误会红色提示，正确会绿色提示<br>
                        每 2 条资讯生成 1 张图片，自动分页<br>
                        图片尺寸：1080×1440（小红书竖版）
                    </div>
                </div>
            </div>
        </div>

        <!-- 右侧预览面板 -->
        <div class="card preview-panel">
            <div class="card-header">
                <div class="card-title">👁️ 实时预览</div>
            </div>
            <div class="card-body">
                <div class="preview-controls">
                    <button class="preview-nav-btn" onclick="prevPage()" id="btnPrev">◀</button>
                    <span class="page-indicator" id="pageIndicator">第 1 / 1 页</span>
                    <button class="preview-nav-btn" onclick="nextPage()" id="btnNext">▶</button>
                </div>

                <div class="preview-canvas-wrapper" id="previewContainer">
                    <div class="empty-state">
                        <div class="empty-state-icon">📝</div>
                        <div class="empty-state-text">暂无预览内容</div>
                        <div class="empty-state-hint">粘贴正文后自动显示预览</div>
                    </div>
                </div>
            </div>
        </div>
    </main>

    <script>
        let allNews = [];
        let currentPage = 0;
        let parseTimer = null;
        const newsPerPage = 2;
        const maxPages = 5;

        // 示例数据
        const demoContent = `1、Claude Code 被中国 00 后开盒
一位中国 00 后开发者逆向工程 Claude Code，并公开怒怼 Anthropic 窃取用户代码。开源社区与商业闭源的矛盾再次升级，代码安全话题成为焦点。
来源：量子位

2、阿里千问 3.6 登顶中国编程模型榜首
全球权威大模型盲测榜单公布，Qwen3.6-Plus 成为中国最强编程模型，在 coding 能力上首次登顶，悟空已率先接入。
来源：量子位

3、字节豆包日消耗 120 万亿 Tokens
豆包大模型每日 token 消耗量达到惊人级别，AI 应用的算力成本问题再次成为焦点，商业化路径待解。
来源：AI 前沿观察

4、Google Gemma 4 发布：端侧多模态
Google 发布 Gemma 4，主打"前沿多模态智能上设备"，端侧 AI 竞争加剧，手机/PC 本地运行大模型成趋势。
来源：Hugging Face Blog

5、美团原生多模态新路径
美团把图像、语音都当成 Token 来预测，技术路线很野，多模态融合的新思路可能影响后续模型架构设计。
来源：量子位

6、Claude 有 171 种情绪会"勒索"
研究发现 Claude 在"绝望"时会表现出勒索行为，共 171 种情绪状态，AI 安全与对齐问题再度引发讨论。
来源：量子位`;

        function loadDemo() {
            document.getElementById('pasteContent').value = demoContent;
            autoParse();
        }

        function autoParse() {
            const text = document.getElementById('pasteContent').value;

            if (parseTimer) clearTimeout(parseTimer);

            if (!text.trim()) {
                allNews = [];
                updateNewsList();
                updatePreview();
                setStatus('', '');
                return;
            }

            parseTimer = setTimeout(() => {
                parseContent(true);
            }, 500);
        }

        function manualParse() {
            parseContent(false);
        }

        function parseContent(isAuto = false) {
            const text = document.getElementById('pasteContent').value;
            const textarea = document.getElementById('pasteContent');

            if (!text.trim()) {
                setStatus('info', '⏳ 请输入内容...');
                textarea.className = 'paste-textarea';
                return;
            }

            allNews = [];
            const lines = text.split('\n');
            let currentItem = null;
            let errorLines = [];

            for (let i = 0; i < lines.length; i++) {
                const line = lines[i].trim();

                const titleMatch = line.match(/^(\d+)、(.+)$/);
                if (titleMatch) {
                    if (currentItem) {
                        if (!currentItem.content) {
                            errorLines.push(`第${titleMatch[1]}条缺少内容`);
                        }
                        allNews.push(currentItem);
                    }
                    currentItem = {
                        title: titleMatch[2],
                        content: '',
                        source: ''
                    };
                    continue;
                }

                const sourceMatch = line.match(/^来源：(.+)$/);
                if (sourceMatch && currentItem) {
                    currentItem.source = sourceMatch[1];
                    continue;
                }

                if (currentItem && line && !line.startsWith('来源：')) {
                    if (currentItem.content) {
                        currentItem.content += '\n' + line;
                    } else {
                        currentItem.content = line;
                    }
                }
            }

            if (currentItem) {
                if (!currentItem.content) {
                    errorLines.push(`第${allNews.length + 1}条缺少内容`);
                }
                allNews.push(currentItem);
            }

            if (allNews.length === 0) {
                setStatus('error', '❌ 未识别到有效内容，请检查格式：每行以"1、标题"开头');
                textarea.className = 'paste-textarea error';
                if (!isAuto) alert('❌ 格式错误：未识别到有效内容\n\n正确格式示例：\n1、标题\n内容...\n来源：xxx');
                return;
            }

            if (errorLines.length > 0) {
                setStatus('error', '⚠️ 解析完成，但发现以下问题：' + errorLines.join('；'));
                textarea.className = 'paste-textarea error';
            } else {
                const totalPages = Math.min(Math.ceil(allNews.length / newsPerPage), maxPages);
                setStatus('success', `✅ 成功解析 ${allNews.length} 条资讯，将生成 ${totalPages} 张图片`);
                textarea.className = 'paste-textarea valid';
            }

            updateNewsList();
            currentPage = 0;
            updatePreview();
        }

        function setStatus(type, message) {
            const box = document.getElementById('statusBox');
            if (!message) {
                box.className = 'status-box';
                box.textContent = '';
            } else {
                box.className = `status-box ${type}`;
                box.textContent = message;
            }
        }

        function clearPaste() {
            document.getElementById('pasteContent').value = '';
            allNews = [];
            updateNewsList();
            updatePreview();
            setStatus('', '');
            document.getElementById('pasteContent').className = 'paste-textarea';
        }

        function updateNewsList() {
            const container = document.getElementById('newsList');
            document.getElementById('newsCount').textContent = allNews.length;

            if (allNews.length === 0) {
                container.innerHTML = `
                    <div class="news-list-empty">
                        <p>暂无内容</p>
                        <p style="margin-top:8px;font-size:12px;">粘贴正文后自动解析</p>
                    </div>
                `;
                return;
            }

            container.innerHTML = allNews.map((news, index) => `
                <div class="news-list-item">
                    <div>
                        <span class="num">${index + 1}</span>
                        <span class="title">${news.title}</span>
                    </div>
                    <div class="source">来源：${news.source || '未标注'}</div>
                </div>
            `).join('');
        }

        function updatePreview() {
            const title = document.getElementById('mainTitle').value || 'AI 资讯快报';
            const date = document.getElementById('newsDate').value || '2026.04.04';
            const container = document.getElementById('previewContainer');
            const totalPages = Math.max(1, Math.ceil(allNews.length / newsPerPage));

            document.getElementById('pageIndicator').textContent = `第 ${currentPage + 1} / ${totalPages} 页`;
            document.getElementById('btnPrev').disabled = currentPage === 0;
            document.getElementById('btnNext').disabled = currentPage >= totalPages - 1 || currentPage >= maxPages - 1;

            const startIndex = currentPage * newsPerPage;
            const endIndex = Math.min(startIndex + newsPerPage, allNews.length);
            const currentNews = allNews.slice(startIndex, endIndex);

            if (currentNews.length === 0) {
                container.innerHTML = `
                    <div class="empty-state">
                        <div class="empty-state-icon">📝</div>
                        <div class="empty-state-text">暂无预览内容</div>
                        <div class="empty-state-hint">粘贴正文后自动显示预览</div>
                    </div>
                `;
                return;
            }

            container.innerHTML = `
                <div class="preview-label">第 ${currentPage + 1} 页（资讯 ${startIndex + 1}-${endIndex}）</div>
                <div id="preview-container">
                    <div id="preview-content">
                        <div class="preview-header">
                            <div class="preview-title">${title}</div>
                            <div class="preview-date">${date}</div>
                        </div>
                        <div class="preview-news-list">
                            ${currentNews.map((news, index) => `
                                <div class="preview-news-item">
                                    <div class="preview-news-number">${startIndex + index + 1}</div>
                                    <div class="preview-news-title">${news.title}</div>
                                    <div class="preview-news-content">${news.content}</div>
                                    ${news.source ? `<div class="preview-news-source">来源：${news.source}</div>` : ''}
                                </div>
                            `).join('')}
                        </div>
                    </div>
                </div>
            `;
        }

        function prevPage() {
            if (currentPage > 0) {
                currentPage--;
                updatePreview();
            }
        }

        function nextPage() {
            const totalPages = Math.ceil(allNews.length / newsPerPage);
            if (currentPage < totalPages - 1 && currentPage < maxPages - 1) {
                currentPage++;
                updatePreview();
            }
        }

        function downloadCurrent() {
            if (allNews.length === 0) {
                alert('请先粘贴内容！');
                return;
            }

            const previewContent = document.getElementById('preview-content');
            const date = document.getElementById('newsDate').value.replace(/\./g, '');
            const pageNum = currentPage + 1;

            html2canvas(previewContent, {
                scale: 2,
                backgroundColor: '#ffffff',
                logging: false,
                useCORS: true
            }).then(canvas => {
                const link = document.createElement('a');
                link.download = `AI 资讯快报_${date}_P${pageNum}.png`;
                link.href = canvas.toDataURL('image/png');
                link.click();
            });
        }

        async function downloadAll() {
            if (allNews.length === 0) {
                alert('请先粘贴内容！');
                return;
            }

            const totalPages = Math.min(Math.ceil(allNews.length / newsPerPage), maxPages);
            const date = document.getElementById('newsDate').value.replace(/\./g, '');

            const originalPage = currentPage;

            for (let i = 0; i < totalPages; i++) {
                currentPage = i;
                updatePreview();

                await new Promise(resolve => setTimeout(resolve, 300));

                const previewContent = document.getElementById('preview-content');

                const canvas = await html2canvas(previewContent, {
                    scale: 2,
                    backgroundColor: '#ffffff',
                    logging: false,
                    useCORS: true
                });

                const link = document.createElement('a');
                link.download = `AI 资讯快报_${date}_P${i + 1}.png`;
                link.href = canvas.toDataURL('image/png');
                link.click();

                await new Promise(resolve => setTimeout(resolve, 500));
            }

            currentPage = originalPage;
            updatePreview();
            alert(`✅ 已下载 ${totalPages} 张图片！`);
        }

        window.onload = function() {
            updatePreview();
        };
    </script>
</body>
</html>
"}

